      ('zephyr-armor', 'Доспех Зефира', 'Этот прекрасный набор бело-серебряных доспехов украшен руной «Ветер» на груди.

Пока вы носите этот доспех, вы совершаете с преимуществом проверки Ловкости (Акробатика) и спасброски Ловкости, поскольку ваши движения поддерживаются нежными потоками ветра.

**_Пробуждение руны_**** _._** Действием вы можете призвать руну брони, чтобы наложить с её помощью заклинание [стена ветров [wind wall]](/spells/337-wind_wall/) (Сл спасброска 15). После того, как руна была пробуждена, она не может быть пробуждена снова до следующего рассвета.', 'armor', 'rare', null, null, 'body', true, 'https://dnd.su/items/6471-zephyr-armor/', 'Bigby Presents: Glory of the Giants')
    ),
    typed_seed as (
      select
        srd_slug::text,
        title_ru::text,
        description_ru::text,
        category::text,
        rarity::text,
        price_gp::numeric,
        weight_lb::numeric,
        slot::text,
        requires_attunement::boolean,
        dndsu_url::text,
        source_detail::text
      from seed
    ),
    inserted as (
      insert into nodes (campaign_id, type_id, title, fields)
      select
        c_rec.id,
        type_id_v,
        s.title_ru,
        jsonb_strip_nulls(jsonb_build_object(
          'srd_slug', s.srd_slug,
          'description', s.description_ru,
          'dndsu_url', s.dndsu_url,
          'source_detail', s.source_detail
        ))
      from typed_seed s
      where not exists (
        select 1 from nodes n
        where n.campaign_id = c_rec.id
          and n.fields->>'srd_slug' = s.srd_slug
      )
      returning id, fields->>'srd_slug' as srd_slug
    )
    insert into item_attributes (
      node_id, category_slug, rarity, price_gp, weight_lb,
      slot_slug, requires_attunement,
      source_slug, availability_slug
    )
    select
      i.id, s.category, s.rarity, s.price_gp, s.weight_lb,
      s.slot, s.requires_attunement,
      'srd-5e', null
    from inserted i
    join typed_seed s on s.srd_slug = i.srd_slug
    on conflict (node_id) do nothing;

    get diagnostics ins_count = row_count;
    raise notice 'Campaign % (%): inserted % new dnd.su items (Bigby Presents: Glory of the Giants)',
      c_rec.slug, c_rec.id, ins_count;
  end loop;
end $$;

-- Phase 2 backfill (transactions.item_node_id = N) is intentionally
-- omitted for dnd.su entries: the canonical Russian title is shared
-- across many similar items and would mis-link prior transactions.
-- DMs do per-item linking on demand from the catalog UI.

commit;
